import{c as t,Q as o,j as a,m as n}from"./chunks/framework.BPKcPtvA.js";const g=JSON.parse('{"title":"Not in this guide","description":"Features that exist in MuHaven but are deliberately excluded from the Testing Guide, and why.","frontmatter":{"title":"Not in this guide","description":"Features that exist in MuHaven but are deliberately excluded from the Testing Guide, and why."},"headers":[],"relativePath":"guide/not-in-this-guide.md","filePath":"guide/not-in-this-guide.md","lastUpdated":1780196777000}'),r={name:"guide/not-in-this-guide.md"};function s(i,e,c,d,h,l){return o(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="not-in-this-guide" tabindex="-1">Not in this guide <a class="header-anchor" href="#not-in-this-guide" aria-label="Permalink to &quot;Not in this guide&quot;">​</a></h1><p>MuHaven has a few surfaces that are <strong>built but not part of this testing guide</strong> — either because they&#39;re still being hardened, or because the on-chain contracts behind them aren&#39;t deployed on the demo testnet. We list them here so you know they exist and why we left them out, rather than letting you hit a dead end mid-evaluation.</p><div class="info custom-block"><p class="custom-block-title">These are intentionally out of scope — not bugs.</p><p>If you find one of these surfaces in the app, it works to the extent described below. We just haven&#39;t written task-by-task test steps for it yet.</p></div><h2 id="hosted-checkout" tabindex="-1">Hosted Checkout <a class="header-anchor" href="#hosted-checkout" aria-label="Permalink to &quot;Hosted Checkout&quot;">​</a></h2><p><strong>What it is:</strong> one-click &quot;pay with a passkey&quot; links an issuer can share, so a buyer can purchase a position without a full dashboard tour.</p><p><strong>Why it&#39;s excluded:</strong> the checkout link / session flow is still in active development and isn&#39;t ready for general testing. Architecture docs live under <a href="/checkout/overview">Hosted Checkout</a>.</p><h2 id="openclaw-—-telegram-bot-phone-first-surfaces" tabindex="-1">OpenClaw — Telegram bot &amp; phone-first surfaces <a class="header-anchor" href="#openclaw-—-telegram-bot-phone-first-surfaces" aria-label="Permalink to &quot;OpenClaw — Telegram bot &amp; phone-first surfaces&quot;">​</a></h2><p><strong>What it is:</strong> a phone-first way to drive your portfolio — a Telegram bot, a device-link flow (<code>/link</code>), and a high-value intent-confirmation deep-link (<code>/agent/confirm</code>).</p><p><strong>Why it&#39;s excluded:</strong> these surfaces aren&#39;t ready for general testing yet. The in-dashboard <a href="/guide/agent/chat">HavenBot</a> and the <a href="/mcp/overview">MCP server</a> cover the same agentic capabilities for testing. Architecture docs live under <a href="/openclaw/overview">OpenClaw</a>.</p><h2 id="p11-—-governance-default-protection-cross-chain-kyc" tabindex="-1">P11 — governance, default protection, cross-chain KYC <a class="header-anchor" href="#p11-—-governance-default-protection-cross-chain-kyc" aria-label="Permalink to &quot;P11 — governance, default protection, cross-chain KYC&quot;">​</a></h2><p><strong>What it is:</strong> three later-wave features —</p><ul><li><strong>Encrypted governance</strong> (propose / vote on encrypted ballots),</li><li><strong>Default protection</strong> (an issuer-funded coverage reserve), and</li><li><strong>Cross-chain KYC attestation</strong> (reuse a KYC claim across chains).</li></ul><p><strong>Why it&#39;s excluded:</strong> the contracts behind these are <strong>not deployed on the demo testnet</strong>. The corresponding agent tools (<code>governance.propose</code>, <code>governance.cast_vote</code>, <code>read.protection_coverage</code>, <code>read.kyc_attestation</code>) deliberately return a clear <strong><code>not_deployed</code></strong> response so you can see the wiring exists without a half-working feature. Treat these as <em>coming soon</em>.</p><hr><p>Everything <strong>else</strong> — the full investor flow, the AI agent (including autonomous execution), and the complete issuer journey — <strong>is</strong> covered. Head back to the <a href="/guide/">Testing Guide overview</a> to pick a track.</p>',15)])])}const p=t(r,[["render",s]]);export{g as __pageData,p as default};
